# Terraform: ASG が複数の AZ で複数のインスタンスタイプを使用することを保証します
resource "aws_autoscaling_group" "<example_resource_name>" {
  name               = "<example_resource_name>"
  min_size           = 1
  max_size           = 1
  vpc_zone_identifier = ["<subnet_id_1>", "<subnet_id_2>"] # 重要：異なる AZ のサブネット

  mixed_instances_policy {
    launch_template {
      launch_template_specification {
        launch_template_name = "<example_resource_name>"
        version              = "$Latest"
      }
      override { instance_type = "<INSTANCE_TYPE_1>" } # 重要：AZ ごとの複数のインスタンスタイプ
      override { instance_type = "<INSTANCE_TYPE_2>" } # 重要：AZ ごとの複数のインスタンスタイプ
    }
  }
}
```
